#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifndef class_T
#define class_T float
#endif

#ifndef BLOCK_STRIDED
#define BLOCK_STRIDED 0
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

#ifndef blockdim
#define blockdim 256
#endif

typedef class_T element_t;

#ifdef ENABLE_HP
typedef short cl_half2[2];
#endif

// Helper function to perform the computation loop
inline element_t compute_iter(element_t val, element_t f) {
  element_t t = val;
  for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
    t = t * t + f;
  }
  return t;
}

__kernel void benchmark_func(element_t seed, __global element_t* src) {
  size_t global_id = get_global_id(0);
  size_t local_id = get_local_id(0);
  size_t group_id = get_group_id(0);

  size_t stride;
  if (BLOCK_STRIDED) {
    stride = blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  } else {
    stride = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  }

  size_t base_idx = (group_id * blockdim + local_id) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

  element_t local_sum = 0;

  for (int fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    size_t idx = base_idx + fusion * ELEMENTS_PER_THREAD;

    #if ELEMENTS_PER_THREAD == 1
      element_t val = src[idx];
      local_sum += compute_iter(val, seed);
    #else
      // Multi-element processing
      element_t f[8];
      // Load f from the first 8 elements of the chunk (or just data[0] repeated if chunk < 8)
      // Based on original logic: f[] = {data[0], data[1], ...}
      for(int k=0; k<8; k++) {
        if (k < ELEMENTS_PER_THREAD) f[k] = src[idx + k];
        else f[k] = src[idx]; // Fallback, though loop bounds prevent access
      }

      for (size_t i = 0; i < ELEMENTS_PER_THREAD; i++) {
        element_t t[8];
        for(int k=0; k<8; k++) t[k] = src[idx + i];

        int full_iters = COMPUTE_ITERATIONS / 8;
        for (int j = 0; j < full_iters; j++) {
          t[0] = t[0] * t[0] + f[0];
          t[1] = t[1] * t[1] + f[1];
          t[2] = t[2] * t[2] + f[2];
          t[3] = t[3] * t[3] + f[3];
          t[4] = t[4] * t[4] + f[4];
          t[5] = t[5] * t[5] + f[5];
          t[6] = t[6] * t[6] + f[6];
          t[7] = t[7] * t[7] + f[7];
        }

        int rem = COMPUTE_ITERATIONS % 8;
        if (rem > 0) t[0] = t[0] * t[0] + f[0];
        if (rem > 1) t[1] = t[1] * t[1] + f[1];
        if (rem > 2) t[2] = t[2] * t[2] + f[2];
        if (rem > 3) t[3] = t[3] * t[3] + f[3];
        if (rem > 4) t[4] = t[4] * t[4] + f[4];
        if (rem > 5) t[5] = t[5] * t[5] + f[5];
        if (rem > 6) t[6] = t[6] * t[6] + f[6];

        local_sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
      }
    #endif
  }

  src[global_id] = local_sum;
}

#ifdef ENABLE_HP
__kernel void benchmark_func_half(cl_half2 seed, __global cl_half2* src) {
  size_t global_id = get_global_id(0);
  size_t local_id = get_local_id(0);
  size_t group_id = get_group_id(0);

  size_t stride;
  if (BLOCK_STRIDED) {
    stride = blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  } else {
    stride = get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE;
  }

  size_t base_idx = (group_id * blockdim + local_id) * ELEMENTS_PER_THREAD * FUSION_DEGREE;

  cl_half2 local_sum = {0, 0};

  for (int fusion = 0; fusion < FUSION_DEGREE; fusion++) {
    size_t idx = base_idx + fusion * ELEMENTS_PER_THREAD;

    #if ELEMENTS_PER_THREAD == 1
      half t0 = src[idx][0];
      half t1 = src[idx][1];
      half f0 = seed[0];
      half f1 = seed[1];

      for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
        t0 = t0 * t0 + f0;
        t1 = t1 * t1 + f1;
      }
      local_sum[0] += t0;
      local_sum[1] += t1;
    #else
      for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
        half t0 = src[idx + i][0];
        half t1 = src[idx + i][1];
        half f0 = seed[0];
        half f1 = seed[1];

        for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
          t0 = t0 * t0 + f0;
          t1 = t1 * t1 + f1;
        }
        local_sum[0] += t0;
        local_sum[1] += t1;
      }
    #endif
  }

  src[global_id] = local_sum;
}
#endif
